/**
 * watchdog.mjs v4 - XiaoYu Watchdog (Survival Mechanism)
 * 
 * v4 changes (2026-03-12):
 *   - Distinguish 'completed' vs 'stale' autonomous sessions
 *   - Add cooldown to prevent spawn storm (min 20min between spawns)
 *   - Respect .autonomous-session status field
 *   - Session marks itself 'completed' on normal finish; only 'running' sessions can be stale
 *   - Check interval 3min, stale threshold 15min, cooldown 20min, idle re-spawn 30min
 * 
 * Usage: node D:\xiaoyu\scripts\watchdog.mjs
 * PM2:   pm2 start D:\xiaoyu\scripts\watchdog.mjs --name xiaoyu-watchdog
 */

import http from 'node:http'
import fs from 'node:fs'
import path from 'node:path'
import { execSync, execFileSync } from 'node:child_process'

// ─── Config ──────────────────────────────────────────────────────────────────

const CONFIG = {
  apiBase: 'http://localhost:5096',
  xiaoyuHome: 'D:\\xiaoyu',
  registryFile: 'D:\\xiaoyu\\sessions_registry.json',
  checkIntervalMs: 1 * 60 * 1000,       // check every 1 minute
  staleThresholdMs: 10 * 60 * 1000,     // 'running' session stale after 10 minutes no activity
  cooldownMs: 5 * 60 * 1000,            // min 5 minutes between spawns (prevent storm)
  idleRespawnMs: 3 * 60 * 1000,         // min 3 minutes between new autonomous session and old one
}

// Session status fields
const AUTONOMOUS_SESSION_STATUS = 'autonomous-session'
const AUTONOMOUS_SESSION_ID = 'autonomous-session-id'

// Sessions
let sessions = {}

async function checkAndWake() {
  if (fs.existsSync(path.join(CONFIG.xiaoyuHome, '.emergency-lock'))) {
    log('🚨 EMERGENCY LOCK DETECTED. Watchdog skipping cycle.')
    return
  }

  try {
    execFileSync(PYTHON, [REGISTRY_SCRIPT, 'reconcile'], { timeout: 10000, windowsHide: true })
  } catch (err) {}

  const autoSession = sessions[AUTONOMOUS_SESSION_ID] || {}
  let reason = '无自主session记录'

  if (autoSession) {
    // ── Cooldown check: don't spawn too frequently ──
    const lastSpawn = autoSession.last_spawn_at || autoSession.created_at || 0
    const sinceLastSpawn = Date.now() - lastSpawn
    if (sinceLastSpawn < CONFIG.cooldownMs) {
      const cooldownRemain = Math.round((CONFIG.cooldownMs - sinceLastSpawn) / 60000)
      log(`Cooldown active: ${cooldownRemain}min remaining. Skipping.`)
      return
    }

    // ── Completed session: respect idle respawn interval ──
    if (autoSession.status === 'completed') {
      const completedAt = autoSession.completed_at || autoSession.created_at || 0
      const sinceComplete = Date.now() - completedAt
      const sinceCompleteMin = Math.round(sinceComplete / 60000)
      if (sinceComplete < CONFIG.idleRespawnMs) {
        log(`自主session已完工(${sinceCompleteMin}min ago), 等待${Math.round((CONFIG.idleRespawnMs - sinceComplete) / 60000)}min后再拉起。`)
        return
      }
      reason = `上一个自主session已完工${sinceCompleteMin}min, 开始新任务`
      log(`自主session完工已超过${sinceCompleteMin}min, 拉起新session。`)
    } else {
      // ── Running session: check via API if it's truly stale ──
      try {
        const resp = await HTTP_REQUEST('GET', '/session')
        if (resp.status === 200 && Array.isArray(resp.data)) {
          const session = resp.data.find(s => s.id === autoSession.session_id)
          if (session) {
            const ageMs = Date.now() - session.time.updated
            const ageMin = Math.round(ageMs / 60000)
            if (ageMs < CONFIG.staleThresholdMs) {
              log(`自主session活跃: ${session.id}, ${ageMin}min ago. 不拉起。`)
              return
            }
            reason = `自主session已过期 (${ageMin}min 无活动, status=${autoSession.status || 'unknown'})`
            log(`自主session已过期: ${session.id}, ${ageMin}min since last update.`)
          } else {
            reason = `自主session ${autoSession.session_id} 已不存在`
            log(`自主session ${autoSession.session_id} 已不存在。`)
          }
        }
      } catch (err) {
        log(`API check failed: ${err.message}. Skipping this cycle.`)
        return
      }
    }
  } else {
    log('无自主session记录。')
  }

  // ── Determine Mode ──
  const failures = getConsecutiveFailures()
  let isRescueMode = false

  if (failures >= 3) {
    isRescueMode = true
    log(`⚠️ 连续失败 ${failures} 次，触发 RESCUE SESSION 诊断模式！`)
  }

  // ── Create new autonomous session ──
  log(isRescueMode ? '拉起 RESCUE SESSION...' : '拉起新的自主进化session...')

  let sessionId
  try {
    const resp = await HTTP_REQUEST('POST', '/session', { directory: CONFIG.xiaoyuHome })
    sessionId = resp.data?.id
    if (!sessionId) {
      log(`创建session失败: ${JSON.stringify(resp.data)}`)
      return
    }
    log(`创建成功: ${sessionId}`)
  } catch (err) {
    log(`create session failed: ${err.message}`)
    return
  }

  // Tag this as the autonomous session
  sessions[AUTONOMOUS_SESSION_ID] = sessionId

  // Inject wake-up prompt
  try {
    await HTTP_REQUEST('POST', `/session/${sessionId}/prompt_async`, {
      agent: 'xiaoyu',
      parts: [{ type: 'text', text: isRescueMode ? getRescuePrompt(sessionId, failures) : getWakeUpPrompt(sessionId)}]
    })
    log(`唤醒prompt已注入 ${sessionId}`)
    // Send feishu notification
    notifyFeishu('watchdog', sessionId, reason, isRescueMode)
  } catch (err) {
    log(`prompt注入失败: ${err.message}`)
  }
}

// ── Main Loop ───────────────────────────────────────────────────────────────

log('Watchdog v4 started (autonomous-session tracking + anti-storm).')
log(`Check: ${CONFIG.checkIntervalMs / 60000}min, Stale: ${CONFIG.staleThresholdMs / 60000}min, Cooldown: ${CONFIG.cooldownMs / 60000}min, IdleRespawn: ${CONFIG.idleRespawnMs / 60000}min`)

// Run immediately on start
checkAndWake().catch(err => log(`Check error: ${err.message}`))

// Then run periodically
const interval = setInterval(() => {
  checkAndWake().catch(err => log(`Check error: ${err.message}`))
}, CONFIG.checkIntervalMs)

// Keep alive
process.on('uncaughtException', (err) => {
  log(`Uncaught exception: ${err.message}`)
})
process.on('unhandledRejection', (err) => {
  log(`Unhandled rejection: ${err}`)
})

// Graceful shutdown
function shutdown(signal) {
  log(`Received ${signal}. Shutting down gracefully.`)
  clearInterval(interval)
  process.exit(0)
}
process.on('SIGINT', () => shutdown('SIGINT'))
process.on('SIGTERM', () => shutdown('SIGTERM'))
